// ── JWT Validation (HS256, pure JS — no external libs) ──────────
const SECRET = 'clawops-workshop-secret-change-in-prod';

// Get token from Authorization header or body
const headers = $input.first().json.headers || {};
const authHeader = headers['authorization'] || headers['Authorization'] || '';
const token = authHeader.startsWith('Bearer ') 
  ? authHeader.slice(7)
  : ($input.first().json.body?.jwt || '');

if (!token) throw new Error('No JWT token provided — request rejected');

// Split token
const parts = token.split('.');
if (parts.length !== 3) throw new Error('Invalid JWT format');
const [headerB64, payloadB64, sigB64] = parts;

// Verify signature (HS256)
const crypto = require('crypto');
const expected = crypto.createHmac('sha256', SECRET)
  .update(`${headerB64}.${payloadB64}`)
  .digest('base64url');

if (expected !== sigB64) throw new Error('Invalid JWT signature — request rejected');

// Verify expiry
const payload = JSON.parse(Buffer.from(payloadB64, 'base64url').toString());
if (!payload.exp || payload.exp < Math.floor(Date.now() / 1000)) {
  throw new Error(`JWT expired at ${new Date(payload.exp*1000).toISOString()} — replay attack prevented`);
}

// JWT valid — pass body to next node
const body = $input.first().json.body || $input.first().json;
return [{ json: { ...body, _jwt_verified: true, _jwt_claims: payload } }];

const body = $input.first().json.body || $input.first().json;
const ev = body.event || body;

// Skip info events
if (!['error','warn'].includes(ev.severity)) {
  return [];  // empty = stop flow
}

// Validate we have real event data
if (!ev.deploy && !ev.name && !ev.reason) {
  return [];  // malformed event — stop
}

// Deduplicate by deploy (not pod name — pod names change on restart)
const store = $getWorkflowStaticData('global');
if (!store.dedup) store.dedup = {};
const key = `${ev.reason}:${ev.deploy || ev.name}:${ev.namespace}`;
const now = Date.now();
if (store.dedup[key] && (now - store.dedup[key]) < 300000) {
  return [];  // deduplicated — stop flow silently
}
store.dedup[key] = now;

// Cleanup
Object.keys(store.dedup).forEach(k => {
  if (now - store.dedup[k] > 600000) delete store.dedup[k];
});

return [{ json: {
  skip: false,
  severity: ev.severity,
  namespace: ev.namespace || 'workshop',
  kind: ev.kind || 'Pod',
  name: ev.name || '',
  reason: ev.reason || '',
  message: ev.message || '',
  deploy: ev.deploy || (ev.name || '').split('-').slice(0,-2).join('-') || ev.name || '',
  node: ev.node || '',
  ts: ev.ts || new Date().toISOString(),
  count: ev.count || 1,
  reasons: ev.reasons || [ev.reason]
}}];

