const agentOut = $input.first().json.output || $input.first().json.error || 'Agent returned no output';
const ev = $('Filter + Dedup').first().json;

// Extract SRE_ACTION if present
const actionMatch = agentOut.match(/SRE_ACTION:\s*(.+)/);
const hasAction = !!actionMatch;
const action = actionMatch ? actionMatch[1].trim() : null;

// Severity icon
const icon = ev.severity === 'error' ? '🔴' : '🟡';

// Build dashboard message
const msg = `${icon} **K8s Event** — \`${ev.reason}\` on \`${ev.deploy}\`\n\n${agentOut}${hasAction ? '\n\n🔐 Awaiting approval — store and approve via TOTP' : ''}`;

return [{ json: {
  message: msg,
  hasAction,
  action,
  severity: ev.severity,
  deploy: ev.deploy,
  namespace: ev.namespace,
  reason: ev.reason,
  agentOutput: agentOut
}}];

const ev = $('Filter + Dedup').first().json;
const incidents = $input.first().json;

// Find open incident for same deploy — from ANY workflow (S5 or S6)
const list = Array.isArray(incidents) ? incidents : (incidents.incidents || []);
const twoHoursAgo = Date.now() - 7200000;

const open = list.find(function(i) {
  if (i.status !== 'pending') return false;
  if (!i.created_at || new Date(i.created_at).getTime() < twoHoursAgo) return false;
  // Match by deploy name in alertname or pod field
  var deploy = ev.deploy || '';
  var alertDeploy = (i.alertname || '').toLowerCase();
  var podDeploy = (i.pod || '').toLowerCase();
  var deployLower = deploy.toLowerCase();
  return alertDeploy.includes(deployLower) || podDeploy.includes(deployLower) || deployLower.includes(alertDeploy.replace('k8s event: ','').split(':')[0]);
});

if (open) {
  return [{ json: {
    alreadyOpen: true,
    existingKey: open.key,
    existingSince: open.created_at,
    existingAlertname: open.alertname,
    deploy: ev.deploy,
    reason: ev.reason,
    namespace: ev.namespace,
    severity: ev.severity,
    count: ev.count || 1,
    reasons: ev.reasons || [ev.reason]
  }}];
}

return [{ json: {
  alreadyOpen: false,
  deploy: ev.deploy,
  reason: ev.reason,
  namespace: ev.namespace,
  severity: ev.severity,
  name: ev.name,
  message: ev.message,
  node: ev.node,
  kind: ev.kind,
  ts: ev.ts,
  count: ev.count || 1,
  reasons: ev.reasons || [ev.reason]
}}];

